class RomajiInput:
    def __init__(self, entry_widget, string_var, on_change_callback):
        self.entry = entry_widget
        self.var = string_var
        self.callback = on_change_callback
        self.confirmed = ""
        self.pending = ""
        self.entry.bind("<KeyPress>", self.on_key)
        
    def update_entry(self):
        self.var.set(self.confirmed + self.pending)
        self.entry.icursor(tk.END)
        self.callback()

    def on_key(self, event):
        keysym = event.keysym.lower() if event.keysym else ""
        char = event.char.lower() if event.char else ""
        
        if keysym in ('backspace', 'delete'):
            if self.pending: self.pending = self.pending[:-1]
            elif self.confirmed: self.confirmed = self.confirmed[:-1]
            self.update_entry()
            return 'break'
            
        if not char or (not char.isalpha() and char != '-'):
            if char.isdigit() or char in "() ":
                self.confirmed += char
                self.update_entry()
                return 'break'
            return None 
            
        self.pending += char
        
        if len(self.pending) >= 2 and self.pending[0] == self.pending[1] and self.pending[0] not in 'aeiouy-':
            self.confirmed += 'ッ'
            self.pending = self.pending[1:]
            
        if len(self.pending) >= 2 and self.pending[0] == 'n' and self.pending[1] not in 'aeiouy-':
            self.confirmed += 'ン'
            self.pending = self.pending[1:]
            
        for length in (3, 2, 1):
            if len(self.pending) >= length:
                prefix = self.pending[:length]
                if prefix in ROMAJI_MAP:
                    self.confirmed += ROMAJI_MAP[prefix]
                    self.pending = self.pending[length:]
                    break 
                    
        self.update_entry()
        return 'break'

def bind_qwerty_num(entry):
    def on_key(event):
        char = event.char.lower() if event.char else ""
        keysym = event.keysym.lower() if event.keysym else ""
        mapping = {'q':'1', 'w':'2', 'e':'3', 'r':'4', 't':'5', 'y':'6', 'u':'7', 'i':'8', 'o':'9', 'p':'0'}
        if char in mapping:
            entry.insert(tk.INSERT, mapping[char])
            return 'break'
        elif keysym in mapping:
            entry.insert(tk.INSERT, mapping[keysym])
            return 'break'
        elif char.isdigit() or keysym in ('backspace', 'delete', 'left', 'right', 'tab'):
            return None 
        return 'break'
    entry.bind('<KeyPress>', on_key)

class SearchDialog:
    def __init__(self, parent, callback):
        self.top = tk.Toplevel(parent)
        self.top.title("Search")
        
        try: self.top.attributes('-fullscreen', True)
        except: pass
        try: self.top.state('zoomed')
        except:
            w, h = parent.winfo_screenwidth(), parent.winfo_screenheight()
            self.top.geometry("{}x{}+0+0".format(w, h))
            
        self.top.grab_set()
        self.callback = callback
        self.search_var = tk.StringVar()
        
        search_frame = tk.Frame(self.top)
        search_frame.pack(fill=tk.X, padx=5, pady=5)
        tk.Label(search_frame, font=("Helvetica", 14)).pack(side=tk.LEFT)
        self.entry = tk.Entry(search_frame, textvariable=self.search_var, font=("Helvetica", 16))
        self.entry.pack(side=tk.LEFT, fill=tk.X, expand=True)
        tk.Button(search_frame, text="閉じる", command=self.top.destroy, bg="#e74c3c", fg="white", font=("Helvetica", 12, "bold")).pack(side=tk.RIGHT, padx=5)
        
        self.romaji = RomajiInput(self.entry, self.search_var, self.update_list)
        
        list_frame = tk.Frame(self.top)
        list_frame.pack(fill=tk.BOTH, expand=True, padx=5, pady=5)
        
        self.lb = tk.Listbox(list_frame, font=("Helvetica", 14, "bold"))
        self.lb.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        
        scroll = tk.Scrollbar(list_frame, command=self.lb.yview, width=30)
        scroll.pack(side=tk.RIGHT, fill=tk.Y)
        self.lb.config(yscrollcommand=scroll.set)
        
        self.lb.bind('<<ListboxSelect>>', self.on_select)
        self.update_list()
        self.entry.focus_set()

    def update_list(self):
        word = self.search_var.get().strip()
        self.lb.delete(0, tk.END)
        count = 0
        for p in POKEMON_DATA:
            if word in p[0]:
                self.lb.insert(tk.END, "{} (A:{} D:{} H:{})".format(p[0], p[1], p[2], p[3]))
                count += 1
                if count >= 50: break

    def on_select(self, event):
        selection = self.lb.curselection()
        if selection:
            text = self.lb.get(selection[0])
            name = text.split(" (")[0]
            for p in POKEMON_DATA:
                if p[0] == name:
                    self.callback(p[0], p[1], p[2], p[3])
                    self.top.destroy()
                    break

class IvGauge(tk.Frame):
    def __init__(self, master, label_text, default_val):
        tk.Frame.__init__(self, master)
        self.var = tk.StringVar(value=default_val)
        
        tk.Label(self, text=label_text, width=7, anchor="e", font=("Helvetica", 12, "bold")).pack(side=tk.LEFT)
        self.entry = tk.Entry(self, textvariable=self.var, width=3, font=("Helvetica", 12, "bold"), justify="center")
        self.entry.pack(side=tk.LEFT, padx=2)
        bind_qwerty_num(self.entry)
        
        self.c_width = 320
        self.c_height = 24
        self.canvas = tk.Canvas(self, width=self.c_width, height=self.c_height, bg="#dcdde1", highlightthickness=0)
        self.canvas.pack(side=tk.LEFT, padx=5, pady=2)
        
        self.rects =[]
        w = self.c_width / 16.0
        for i in range(16):
            x0 = i * w
            x1 = x0 + w
            rect = self.canvas.create_rectangle(x0, 0, x1, self.c_height, fill="#bdc3c7", outline="white", width=1)
            self.rects.append(rect)
            
        for i in[1, 6, 11]:
            x = i * w
            self.canvas.create_line(x, 0, x, self.c_height, fill="#2c3e50", width=2)
            
        self.canvas.bind("<Button-1>", self.on_touch)
        self.canvas.bind("<B1-Motion>", self.on_touch)
        self.var.trace("w", self.draw)
        self.draw()

    def on_touch(self, event):
        val = int(event.x / (self.c_width / 16.0))
        if val < 0: val = 0
        if val > 15: val = 15
        self.var.set(str(val))
        
    def draw(self, *args):
        try: val = int(self.var.get() or 0)
        except ValueError: val = 0
            
        color = "#e74c3c" if val == 15 else ("#f39c12" if val >= 10 else "#3498db")
        unselected_color = "#bdc3c7"
        
        for i in range(16):
            fill_c = color if i <= val else unselected_color
            self.canvas.itemconfig(self.rects[i], fill=fill_c)

def get_ideal_ivs(base_a, base_d, base_h, limit, max_pl_idx):
    cpm_local = CPM_LIST
    cpm2_local = CPM2_LIST
    
    atk_list =[base_a + i for i in xrange(16)]
    def_list =[base_d + i for i in xrange(16)]
    hp_list =[base_h + i for i in xrange(16)]
    sqrt_def =[math.sqrt(d) for d in def_list]
    
    hp_st_table = [[int(hp_list[h] * c) for c in cpm_local] for h in range(16)]
    scp_factor_table = [[cpm2_local[pl] * hp_st_table[h][pl] for pl in range(len(cpm_local))] for h in range(16)]
    inv_sqrt_hp =[1.0 / math.sqrt(h) for h in hp_list]
    h_info =[(inv_sqrt_hp[h], hp_st_table[h], scp_factor_table[h]) for h in range(16)]

    best_prod = -1.0
    best_hp = -1
    best_ivs =[]

    pl_start = max_pl_idx
    for a in xrange(16):
        atk_val = atk_list[a]
        pl_d = pl_start
        for d in xrange(16):
            def_val = def_list[d]
            ad_val = atk_val * sqrt_def[d] / 10.0
            atk_def_val = atk_val * def_val
            inv_ad = 1.0 / ad_val
            
            if limit == 100000 or limit == 40:
                target_pl_idx = 80 if limit == 40 else max_pl_idx
                for h in xrange(16):
                    hp_st = hp_st_table[h][target_pl_idx]
                    prod = atk_def_val * scp_factor_table[h][target_pl_idx]
                    
                    if prod > best_prod + 1e-5:
                        best_prod = prod
                        best_hp = hp_st
                        best_ivs =[(a, d, h, target_pl_idx)]
                    elif prod >= best_prod - 1e-5:
                        if hp_st > best_hp:
                            best_hp = hp_st
                            best_ivs = [(a, d, h, target_pl_idx)]
                        elif hp_st == best_hp:
                            best_ivs.append((a, d, h, target_pl_idx))
            else:
                lim_mul = (limit + 1) * inv_ad
                pl_h = pl_d
                for h in xrange(16):
                    inv_sq, hp_st_row, scp_factor_row = h_info[h]
                    lim = lim_mul * inv_sq
                    while pl_h > 2 and cpm2_local[pl_h] >= lim: pl_h -= 1
                    if h == 0: pl_d = pl_h
                    if d == 0 and h == 0: pl_start = pl_h
                    
                    hp_st = hp_st_row[pl_h]
                    prod = atk_def_val * scp_factor_row[pl_h]
                    
                    if prod > best_prod + 1e-5:
                        best_prod = prod
                        best_hp = hp_st
                        best_ivs =[(a, d, h, pl_h)]
                    elif prod >= best_prod - 1e-5:
                        if hp_st > best_hp:
                            best_hp = hp_st
                            best_ivs = [(a, d, h, pl_h)]
                        elif hp_st == best_hp:
                            best_ivs.append((a, d, h, pl_h))
                            
    results =[]
    for (a, d, h, pl_idx) in best_ivs:
        cpm = cpm_local[pl_idx]
        cp = int(atk_list[a] * math.sqrt(def_list[d]) * math.sqrt(hp_list[h]) * cpm * cpm / 10.0)
        if limit == 100000 or limit == 40:
            results.append(" {}/{}/{} (CP: {})".format(a, d, h, max(10, cp)))
        else:
            results.append(" {}/{}/{} (PL: {} / CP: {})".format(a, d, h, pl_idx/2.0, max(10, cp)))
            
    scp = int((best_prod ** (2.0/3.0)) / 10.0)
    return results, scp

class IdealDialog:
    def __init__(self, parent, base_a, base_d, base_h, max_pl_idx):
        self.top = tk.Toplevel(parent)
        self.top.title("Best IV")
        
        try: self.top.attributes('-fullscreen', True)
        except: pass
        try: self.top.state('zoomed')
        except:
            w, h = parent.winfo_screenwidth(), parent.winfo_screenheight()
            self.top.geometry("{}x{}+0+0".format(w, h))
            
        self.top.grab_set()
        
        tk.Label(self.top, text="理想個体 (1位)", font=("Helvetica", 14, "bold"), fg="#e74c3c").pack(side=tk.TOP, pady=5)
        
        tk.Button(self.top, text="閉じる", command=self.top.destroy, bg="#34495e", fg="white", font=("Helvetica", 14, "bold")).pack(side=tk.BOTTOM, fill=tk.X, padx=10, pady=5)
        
        frame = tk.Frame(self.top)
        frame.pack(side=tk.TOP, fill=tk.BOTH, expand=True, padx=10, pady=5)
        
        text_widget = tk.Text(frame, font=("Helvetica", 12), state=tk.NORMAL)
        scroll = tk.Scrollbar(frame, command=text_widget.yview, width=30)
        text_widget.configure(yscrollcommand=scroll.set)
        text_widget.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        scroll.pack(side=tk.RIGHT, fill=tk.Y)
        
        limits =[500, 1500, 2500, 40, 100000]
        limit_names =["【リトル】", "【スーパー】", "【ハイパー】", "【マスター (PL40)】", "【マスター (Max)】"]
        
        for i, limit in enumerate(limits):
            res_list, scp = get_ideal_ivs(base_a, base_d, base_h, limit, max_pl_idx)
            text_widget.insert(tk.END, "{}\n SCP: {}\n".format(limit_names[i], scp))
            for res in res_list:
                text_widget.insert(tk.END, "  {}\n".format(res))
            text_widget.insert(tk.END, "\n")
            
        text_widget.config(state=tk.DISABLED)

